    if (_brightnessChar == null) {
      throw const Failure.connection(
        message: 'Brightness characteristic not available',
      );
    }

    try {
      final bytes = await _brightnessChar!.read();
      if (bytes.length >= 4) {
        final byteData = ByteData.view(Uint8List.fromList(bytes).buffer);
        final brightness = byteData.getUint32(0, Endian.little);
        print('=== [ILENS BRIGHTNESS] Read brightness: $brightness%');
        developer.log('[ILENS] Read brightness: $brightness%', name: 'runvision');
        return brightness.clamp(0, 100);
      }
      return 50; // Default if read fails
    } catch (e) {
      print('=== [ILENS BRIGHTNESS] ❌ Read failed: $e');
      developer.log('[ILENS] Brightness read failed: $e', name: 'runvision');
      return 50; // Default
    }
  }

  /// Check if brightness control is available
  bool get isBrightnessAvailable => _brightnessChar != null;

  /// Enable or disable screen activity (battery polling & keep-alive)
  ///
  /// When disabled, no READ operations are performed, allowing
  /// hibernation timer to work correctly.
  ///
  /// [enabled] true to enable polling, false to disable
  void setScreenActivityEnabled(bool enabled) {
    _screenActivityEnabled = enabled;
    print('=== [ILENS] Screen activity ${enabled ? "ENABLED" : "DISABLED"}');

    if (enabled) {
      // Resume polling if connected
      if (_connectedDevice != null && _batteryChar != null) {
        _subscribeToBattery();
        _startKeepAlive();
      }
    } else {
      // Stop all polling to allow hibernation
      _batteryPollTimer?.cancel();
      _batteryPollTimer = null;
      _stopKeepAlive();
    }
  }

  /// Check if screen activity (polling) is enabled
  bool get isScreenActivityEnabled => _screenActivityEnabled;

