  /// Queue a BLE write operation to prevent simultaneous writes
  Future<void> _queueWrite(Future<void> Function() writeOperation) async {
    final completer = Completer<void>();

    _writeQueue.add(() async {
      try {
        await writeOperation();
        completer.complete();
      } catch (e) {
        completer.completeError(e);
      }
    });

    _processWriteQueue();
    return completer.future;
  }

  /// Process write queue sequentially
  Future<void> _processWriteQueue() async {
    if (_isProcessingQueue || _writeQueue.isEmpty) return;

    _isProcessingQueue = true;
    print('=== [ILENS QUEUE] Starting queue processing (${_writeQueue.length} items)');

    while (_writeQueue.isNotEmpty) {
      final operation = _writeQueue.removeAt(0);
      try {
        await operation();
        print('=== [ILENS QUEUE] ✓ Operation completed');
      } catch (e) {
        print('=== [ILENS QUEUE] ⚠️ Operation failed: $e');
        // Continue processing queue even if one operation fails
      }
    }

    _isProcessingQueue = false;
    print('=== [ILENS QUEUE] Queue processing complete');
  }

  Future<void> _discoverServices() async {
    print('=== [ILENS DISCOVER] Calling discoverServices()...');
    final services = await _connectedDevice!.discoverServices();
    print('=== [ILENS DISCOVER] Discovered ${services.length} services');
    developer.log('[ILENS] Discovered ${services.length} services', name: 'runvision');

    for (var service in services) {
      print('=== [ILENS DISCOVER]   Service: ${service.uuid.str}');
      developer.log('[ILENS]   Service: ${service.uuid.str}', name: 'runvision');
      for (var char in service.characteristics) {
        print('=== [ILENS DISCOVER]     Char: ${char.uuid.str}');
        developer.log('[ILENS]     Char: ${char.uuid.str}', name: 'runvision');
      }
    }

    print('=== [ILENS DISCOVER] Searching for iLens Service UUID: $ilensServiceUuid');
    // Try to find iLens service (case insensitive, with or without dashes)
    final ilensService = services.firstWhere(
      (s) {
        final serviceUuid = s.uuid.str.toLowerCase().replaceAll('-', '');
        final targetUuid = ilensServiceUuid.toLowerCase().replaceAll('-', '');
        print('=== [ILENS DISCOVER] Comparing: ${s.uuid.str} (normalized: $serviceUuid) with target: $ilensServiceUuid (normalized: $targetUuid)');
        developer.log('[ILENS] Comparing service ${s.uuid.str} with target $ilensServiceUuid', name: 'runvision');
        return serviceUuid == targetUuid;
      },
      orElse: () {
        print('=== [ILENS DISCOVER] ERROR: iLens Service not found! Available services:');
        developer.log('[ILENS] ERROR: iLens Service not found! Available services:', name: 'runvision');
        for (var s in services) {
          print('=== [ILENS DISCOVER]   - ${s.uuid.str}');
          developer.log('[ILENS]   - ${s.uuid.str}', name: 'runvision');
        }
        throw const Failure.connection(
          message: 'iLens Service not found',
        );
      },
    );
    print('=== [ILENS DISCOVER] Found iLens Service: ${ilensService.uuid.str}');
    developer.log('[ILENS] Found iLens Service: ${ilensService.uuid.str}', name: 'runvision');

    // iLens uses a single characteristic for all communication
    final mainChar = ilensService.characteristics.firstWhere(
      (c) {
        final charUuid = c.uuid.str.toLowerCase().replaceAll('-', '');
        final targetUuid = configCharUuid.toLowerCase().replaceAll('-', '');
        return charUuid == targetUuid;
      },
      orElse: () => throw const Failure.connection(
        message: 'Main Characteristic (c259c1bd-18d3-c348-b88d-5447aea1b615) not found',
      ),
    );

    // Use the same characteristic for config and data operations
    _configChar = mainChar;
    _dataChar = mainChar;
    print('=== [ILENS DISCOVER] ✓ Found Main Characteristic: ${mainChar.uuid.str}');
    developer.log('[ILENS] Found Main Characteristic: ${mainChar.uuid.str}', name: 'runvision');

    // Find battery characteristic (separate from main char)
    // Battery is in Device configuration services (58211C97-482A-2808-2D3E-228405F1E749)
    final batteryService = services.firstWhere(
      (s) {
        final serviceUuid = s.uuid.str.toLowerCase().replaceAll('-', '');
        const targetUuid = '58211c97482a28082d3e228405f1e749';
        return serviceUuid == targetUuid;
      },
      orElse: () {
        print('=== [ILENS DISCOVER] Battery service not found, battery monitoring disabled');
        developer.log('[ILENS] Battery service not found, battery monitoring disabled', name: 'runvision');
        return null as BluetoothService;
      },
    );

    try {
      _batteryChar = batteryService.characteristics.firstWhere(
        (c) {
          final charUuid = c.uuid.str.toLowerCase().replaceAll('-', '');
          final targetUuid = batteryCharUuid.toLowerCase().replaceAll('-', '');
          return charUuid == targetUuid;
        },
      );
      print('=== [ILENS DISCOVER] ✓ Found Battery Characteristic: ${_batteryChar!.uuid.str}');
      developer.log('[ILENS] Found Battery Characteristic: ${_batteryChar!.uuid.str}', name: 'runvision');
    } catch (e) {
      print('=== [ILENS DISCOVER] Battery characteristic not found in service');
      developer.log('[ILENS] Battery characteristic not found in service', name: 'runvision');
    }

    // Find Current Time characteristic in the same Device Configuration Service
    try {
      print('=== [ILENS DISCOVER] Looking for Current Time characteristic: $currentTimeCharUuid');
      print('=== [ILENS DISCOVER] Available characteristics in Device Configuration Service:');
      for (final char in batteryService.characteristics) {
        print('  - ${char.uuid.str} (write: ${char.properties.write}, read: ${char.properties.read})');
      }

      _currentTimeChar = batteryService.characteristics.firstWhere(
        (c) {
          final charUuid = c.uuid.str.toLowerCase().replaceAll('-', '');
          final targetUuid = currentTimeCharUuid.toLowerCase().replaceAll('-', '');
          print('=== [ILENS DISCOVER] Comparing: $charUuid vs $targetUuid');
          return charUuid == targetUuid;
        },
      );
      print('=== [ILENS DISCOVER] ✓ Found Current Time Characteristic: ${_currentTimeChar!.uuid.str}');
      print('=== [ILENS DISCOVER] ✓ Properties: write=${_currentTimeChar!.properties.write}, read=${_currentTimeChar!.properties.read}');
      developer.log('[ILENS] Found Current Time Characteristic: ${_currentTimeChar!.uuid.str}', name: 'runvision');
    } catch (e) {
      print('=== [ILENS DISCOVER] ❌ Current Time characteristic not found in service: $e');
      developer.log('[ILENS] Current Time characteristic not found in service', name: 'runvision');
    }

    // Find Hibernation Time characteristic in the same Device Configuration Service
    try {
      print('=== [ILENS DISCOVER] Looking for Hibernation Time characteristic: $hibernationTimeCharUuid');
      _hibernationTimeChar = batteryService.characteristics.firstWhere(
        (c) {
          final charUuid = c.uuid.str.toLowerCase().replaceAll('-', '');
          final targetUuid = hibernationTimeCharUuid.toLowerCase().replaceAll('-', '');
          print('=== [ILENS DISCOVER] Comparing: $charUuid vs $targetUuid');
          return charUuid == targetUuid;
        },
      );
      print('=== [ILENS DISCOVER] ✓ Found Hibernation Time Characteristic: ${_hibernationTimeChar!.uuid.str}');
      print('=== [ILENS DISCOVER] ✓ Properties: write=${_hibernationTimeChar!.properties.write}, read=${_hibernationTimeChar!.properties.read}');
      developer.log('[ILENS] Found Hibernation Time Characteristic: ${_hibernationTimeChar!.uuid.str}', name: 'runvision');
    } catch (e) {
      print('=== [ILENS DISCOVER] ❌ Hibernation Time characteristic not found in service: $e');
      developer.log('[ILENS] Hibernation Time characteristic not found in service', name: 'runvision');
    }

    // Find Brightness characteristic in the same Device Configuration Service
    try {
      print('=== [ILENS DISCOVER] Looking for Brightness characteristic: $brightnessCharUuid');
      _brightnessChar = batteryService.characteristics.firstWhere(
        (c) {
          final charUuid = c.uuid.str.toLowerCase().replaceAll('-', '');
          final targetUuid = brightnessCharUuid.toLowerCase().replaceAll('-', '');
          print('=== [ILENS DISCOVER] Comparing: $charUuid vs $targetUuid');
          return charUuid == targetUuid;
        },
      );
      print('=== [ILENS DISCOVER] ✓ Found Brightness Characteristic: ${_brightnessChar!.uuid.str}');
      print('=== [ILENS DISCOVER] ✓ Properties: write=${_brightnessChar!.properties.write}, read=${_brightnessChar!.properties.read}');
      developer.log('[ILENS] Found Brightness Characteristic: ${_brightnessChar!.uuid.str}', name: 'runvision');
    } catch (e) {
      print('=== [ILENS DISCOVER] ⚠️ Brightness characteristic not found in service: $e');
      developer.log('[ILENS] Brightness characteristic not found in service (may not be supported by this device)', name: 'runvision');
    }

    // Find Screen OFF Time characteristic (자동깨우기)
    // rLens BLE Protocol v1.0.1: UUID 09f8e7d6-c5b4-a392-8170-6f5e4d3c2ba1
    try {
      print('=== [ILENS DISCOVER] Looking for Screen OFF Time characteristic: $screenOffTimeCharUuid');
      _screenOffTimeChar = batteryService.characteristics.firstWhere(
        (c) {
          final charUuid = c.uuid.str.toLowerCase().replaceAll('-', '');
          final targetUuid = screenOffTimeCharUuid.toLowerCase().replaceAll('-', '');
          print('=== [ILENS DISCOVER] Comparing: $charUuid vs $targetUuid');
          return charUuid == targetUuid;
        },
      );
      print('=== [ILENS DISCOVER] ✓ Found Screen OFF Time Characteristic: ${_screenOffTimeChar!.uuid.str}');
      print('=== [ILENS DISCOVER] ✓ Properties: write=${_screenOffTimeChar!.properties.write}, read=${_screenOffTimeChar!.properties.read}');
      developer.log('[ILENS] Found Screen OFF Time Characteristic: ${_screenOffTimeChar!.uuid.str}', name: 'runvision');
    } catch (e) {
      print('=== [ILENS DISCOVER] ⚠️ Screen OFF Time characteristic not found in service: $e');
      developer.log('[ILENS] Screen OFF Time characteristic not found in service (may not be supported by this device)', name: 'runvision');
    }

    // Find Device State characteristic (CRITICAL: Must be read before writing settings!)
    // This characteristic was discovered from iLens official app behavior
    try {
      print('=== [ILENS DISCOVER] Looking for Device State characteristic: $deviceStateCharUuid');
      _deviceStateChar = batteryService.characteristics.firstWhere(
        (c) {
          final charUuid = c.uuid.str.toLowerCase().replaceAll('-', '');
          final targetUuid = deviceStateCharUuid.toLowerCase().replaceAll('-', '');
          print('=== [ILENS DISCOVER] Comparing: $charUuid vs $targetUuid');
          return charUuid == targetUuid;
        },
      );
      print('=== [ILENS DISCOVER] ✓ Found Device State Characteristic: ${_deviceStateChar!.uuid.str}');
      print('=== [ILENS DISCOVER] ✓ Properties: write=${_deviceStateChar!.properties.write}, read=${_deviceStateChar!.properties.read}');
      developer.log('[ILENS] Found Device State Characteristic: ${_deviceStateChar!.uuid.str}', name: 'runvision');
    } catch (e) {
      print('=== [ILENS DISCOVER] ⚠️ Device State characteristic not found in service: $e');
      developer.log('[ILENS] Device State characteristic not found in service', name: 'runvision');
    }

    // Find Universal Subscriptions characteristic (CRITICAL for initialization!)
    // iLens BLE V1.0.10.pdf Section 3.7
    // This characteristic MUST be written to with initialization commands BEFORE any settings writes
    try {
      print('=== [ILENS DISCOVER] Looking for Universal Subscriptions characteristic: $universalSubCharUuid');
      _universalSubChar = batteryService.characteristics.firstWhere(
        (c) {
          final charUuid = c.uuid.str.toLowerCase().replaceAll('-', '');
          final targetUuid = universalSubCharUuid.toLowerCase().replaceAll('-', '');
          print('=== [ILENS DISCOVER] Comparing: $charUuid vs $targetUuid');
          return charUuid == targetUuid;
        },
      );
      print('=== [ILENS DISCOVER] ✓ Found Universal Subscriptions Characteristic: ${_universalSubChar!.uuid.str}');
      print('=== [ILENS DISCOVER] ✓ Properties: write=${_universalSubChar!.properties.write}, notify=${_universalSubChar!.properties.notify}');
      developer.log('[ILENS] Found Universal Subscriptions Characteristic: ${_universalSubChar!.uuid.str}', name: 'runvision');
    } catch (e) {
      print('=== [ILENS DISCOVER] ❌ CRITICAL: Universal Subscriptions characteristic not found: $e');
      developer.log('[ILENS] CRITICAL: Universal Subscriptions characteristic not found - device initialization will fail!', name: 'runvision');
    }
    }

  /// Poll battery level every 1 second (READ operation)
  Future<void> _subscribeToBattery() async {
    if (_batteryChar == null) {
      print('=== [ILENS BATTERY] Battery characteristic not available, skipping battery monitoring');
      developer.log('[ILENS] Battery characteristic not available, skipping battery monitoring', name: 'runvision');
      return;
    }

    // Poll battery every 60 seconds via READ operation (reduced from 1s to minimize screen wake-ups)
    _batteryPollTimer?.cancel();
    _batteryPollTimer = Timer.periodic(const Duration(seconds: 60), (_) async {
      // Skip battery polling if screen activity is disabled (for hibernation testing)
      if (!_screenActivityEnabled) {
        return;
      }

      try {
        final bytes = await _batteryChar!.read();
        if (bytes.isNotEmpty) {
          final status = _parseBatteryStatus(bytes);
          _statusController.add(status);
          developer.log('[ILENS] Battery: ${status.batteryLevel}%', name: 'runvision');
        }
      } catch (e) {
        developer.log('[ILENS] Battery read error: $e', name: 'runvision');
      }
    });

    // Also read battery immediately on connect
    try {
      final bytes = await _batteryChar!.read();
      if (bytes.isNotEmpty) {
        final status = _parseBatteryStatus(bytes);
        _statusController.add(status);
        print('=== [ILENS BATTERY] Initial battery level: ${status.batteryLevel}%');
      }
    } catch (e) {
      print('=== [ILENS BATTERY] Initial battery read failed: $e');
    }

    print('=== [ILENS BATTERY] Started 60-second battery polling');
    developer.log('[ILENS] Started 60-second battery polling', name: 'runvision');
  }

  /// CONFIG 패킷 인코딩 - UI Sorting (Protocol V1.0.10 Section 4.3)
  ///
  /// Packet Structure (21 bytes):
  ///   [0]      Command ID = 0x00 (UI Sorting)
  ///   [1-20]   Data: 10 pairs of (index, type)
  ///            Each pair: index (0-9) + metric type id
  ///            Unused positions: 0xFF (hidden/invalid)
  List<int> _encodeConfig(ILensConfig config) {
    print('=== [ILENS ENCODE] Encoding UI sorting config');

    // UI sorting packet: 1 byte id + 20 bytes data = 21 bytes total
    final bytes = List<int>.filled(21, 0);
    bytes[0] = 0x00; // UI sorting command

    // Configure display layout: index 0-9, each with metric type
    // Fill all 10 positions to prevent empty items from showing
    for (int i = 0; i < 10; i++) {
      bytes[1 + (i * 2)] = i; // index (0-9)

      if (i < config.metrics.length) {
        // Valid metric: use actual metric ID
        bytes[1 + (i * 2) + 1] = config.metrics[i].id;
        print('=== [ILENS ENCODE] Position $i: metric id 0x${config.metrics[i].id.toRadixString(16).padLeft(2, '0')} (${_getMetricName(config.metrics[i].id)})');
      } else {
        // Unused position: set to 0xFF to hide from display
        bytes[1 + (i * 2) + 1] = 0xFF;
        print('=== [ILENS ENCODE] Position $i: HIDDEN (0xFF)');
      }
    }

    print('=== [ILENS ENCODE] UI sorting packet: ${bytes.map((b) => '0x${b.toRadixString(16).padLeft(2, '0')}').join(' ')}');
    return bytes;
  }

  /// Get metric name for logging
  String _getMetricName(int metricId) {
    switch (metricId) {
      case 0x07: return 'speed';
      case 0x0B: return 'heartRate';
      case 0x0E: return 'cadence';
      default: return 'unknown';
    }
  }

  /// CURRENT TIME 패킷 인코딩 (iLens BLE V1.0.10 Section 3.3)
  ///
  /// Packet Structure (10 bytes):
  ///   [0-1]  year (UINT16, little-endian)
  ///   [2]    month (UINT8, 1-12)
  ///   [3]    day (UINT8, 1-31)
  ///   [4]    hour (UINT8, 0-23, UTC 기준)
  ///   [5]    minute (UINT8, 0-59)
  ///   [6]    second (UINT8, 0-59)
  ///   [7]    dayOfWeek (UINT8, 1=Mon...7=Sun, 0=Unknown)
  ///   [8]    fraction256 (UINT8, 1/256 second, usually 0)
  ///   [9]    reason (UINT8)
  ///
  /// Two-stage synchronization (per iLens firmware architecture):
  /// Stage 1 (reason=0x02): UTC time → UI layer update
  /// Stage 2 (reason=0x03): UTC time + timezone flag → RTC sync trigger
  ///
  /// [reason] Adjust Reason code (0x02 or 0x03)
  List<int> _encodeCurrentTime(DateTime dateTime, {int reason = 0x03}) {
    // Send LOCAL time with 2-stage sync for proper RTC update
    // Stage 1 (reason 0x02): LOCAL time → UI layer update
    // Stage 2 (reason 0x03): LOCAL time + timezone flag → RTC sync trigger
    final timeToSend = dateTime;  // USE LOCAL, NOT UTC

    print('=== [ILENS TIME] Local time: ${dateTime.toString()}');
    print('=== [ILENS TIME] Sending LOCAL time (not UTC)');
    print('=== [ILENS TIME] Reason: 0x${reason.toRadixString(16).padLeft(2, '0')} (${reason == 0x02 ? "External Reference" : "Timezone Change"})');

    final bytes = List<int>.filled(10, 0);

    // Year (UINT16, little-endian)
    final year = timeToSend.year;
    bytes[0] = year & 0xFF;          // Low byte
    bytes[1] = (year >> 8) & 0xFF;   // High byte

    // Month (1-12)
    bytes[2] = timeToSend.month;

    // Day (1-31)
    bytes[3] = timeToSend.day;

    // Hour (0-23, LOCAL)
    bytes[4] = timeToSend.hour;

    // Minute (0-59)
    bytes[5] = timeToSend.minute;

    // Second (0-59)
    bytes[6] = timeToSend.second;

    // DayOfWeek (1=Mon, 2=Tue, ..., 7=Sun)
    // DateTime.weekday: 1=Mon, 7=Sun (same as BLE standard)
    bytes[7] = timeToSend.weekday;

    // Fraction256 (1/256 second, set to 0)
    bytes[8] = 0x00;

    // Reason (0x02 or 0x03)
    bytes[9] = reason;

    print('=== [ILENS TIME] Time packet: ${bytes.map((b) => '0x${b.toRadixString(16).padLeft(2, '0')}').join(' ')}');
    print('=== [ILENS TIME] Year: $year, Month: ${timeToSend.month}, Day: ${timeToSend.day}');
    print('=== [ILENS TIME] LOCAL Time: ${timeToSend.hour}:${timeToSend.minute}:${timeToSend.second}, DayOfWeek: ${timeToSend.weekday}');

    return bytes;
  }

  /// METRIC 패킷 인코딩 - Exercise Data (Protocol V1.0.10 Section 4.3)
  ///
  /// Packet Structure (5 bytes):
  ///   [0]     Metric ID (UINT8)
  ///           0x02 = Calories (kcal)
  ///           0x06 = Distance (cm) - 100을 곱해서 소숫점 두 자리 보존
  ///           0x07 = Speed (km/h * 10) - 10을 곱해서 소숫점 한 자리 보존
  ///           0x0B = Heart Rate (bpm)
  ///           0x0E = Cadence (spm)
  ///   [1-4]   Value (UINT32, Little-Endian)
  List<int> _encodeMetric(ILensMetric metric) {
    print('=== [ILENS ENCODE] Encoding metric - Type: 0x${metric.type.id.toRadixString(16).padLeft(2, '0')}, Value: ${metric.value}');

    // Exercise data packet: 1 byte id + 4 bytes data = 5 bytes total
    final bytes = List<int>.filled(5, 0);
    bytes[0] = metric.type.id;

    // Convert value to UINT32
    // Per iLens BLE V1.0.10 PDF Section 4.3:
    // - distance (0x06): UINT32, Unit: meters (정수로 반올림)
    // - velocity (0x07): UINT32, Unit: km/h (정수로 반올림)
    // - calories (0x02): UINT32, Unit: kcal (정수로 반올림)
    // - All other metrics: UINT32, round to integer
    //
    // NOTE: iLens 하드웨어가 소숫점 표시를 지원하는지 확인 필요
    // 현재는 프로토콜 문서대로 정수 값만 전송
    final value = metric.value.round().clamp(0, 4294967295);
    print('=== [ILENS ENCODE] ${metric.type.toString()}: ${metric.value.toStringAsFixed(2)} → $value (rounded to integer)');

    // Encode as UINT32 little-endian
    final byteData = ByteData(4);
    byteData.setUint32(0, value, Endian.little);
    bytes[1] = byteData.getUint8(0);
    bytes[2] = byteData.getUint8(1);
    bytes[3] = byteData.getUint8(2);
    bytes[4] = byteData.getUint8(3);

    print('=== [ILENS ENCODE] Metric packet: ${bytes.map((b) => '0x${b.toRadixString(16).padLeft(2, '0')}').join(' ')}');
    return bytes;
  }

  /// BATTERY 패킷 파싱 (iLens BLE V1.0.10.pdf Section 3.2)
  ///
  /// Battery Level: UINT8 (0-100)
  /// [bytes] Battery READ 바이트
  /// Returns: ILensStatus
  ILensStatus _parseBatteryStatus(List<int> bytes) {
    print('=== [ILENS BATTERY] Raw bytes: ${bytes.map((b) => '0x${b.toRadixString(16).padLeft(2, '0')}').join(' ')}');

    // Battery is simple UINT8 (0-100)
    int batteryLevel = 0;
    if (bytes.isNotEmpty) {
      batteryLevel = bytes[0].clamp(0, 100);
      print('=== [ILENS BATTERY] Battery level: $batteryLevel%');
    }

    return ILensStatus(
      isConnected: true,  // We're reading battery, so we're connected
      batteryLevel: batteryLevel,
      timestamp: DateTime.now(),
      firmwareVersion: _firmwareVersion,
    );
  }

  /// Keep-alive 타이머 시작
  void _startKeepAlive() {
    _stopKeepAlive();

    print('=== [ILENS KEEPALIVE] Starting keep-alive timer (${_keepAliveInterval.inSeconds}s interval)');
    developer.log('[ILENS] Starting keep-alive timer', name: 'runvision');

    _keepAliveTimer = Timer.periodic(_keepAliveInterval, (timer) async {
      // Skip keep-alive if screen activity is disabled (for hibernation testing)
      if (!_screenActivityEnabled) {
        return;
      }

      if (_batteryChar != null && _connectedDevice != null) {
        try {
          // Read battery characteristic to keep connection alive
          print('=== [ILENS KEEPALIVE] Sending keep-alive request');
          await _batteryChar!.read();
          print('=== [ILENS KEEPALIVE] Keep-alive successful');
        } catch (e) {
          print('=== [ILENS KEEPALIVE] Keep-alive failed: $e');
          developer.log('[ILENS] Keep-alive failed: $e', name: 'runvision');
        }
      }
    });
  }

  /// Keep-alive 타이머 중지
  void _stopKeepAlive() {
    _keepAliveTimer?.cancel();
    _keepAliveTimer = null;
    print('=== [ILENS KEEPALIVE] Keep-alive timer stopped');
  }

  /// 연결 해제 처리 (자동 재연결 포함)
  void _handleDisconnection() {
    print('=== [ILENS RECONNECT] Handling disconnection, auto-reconnect=$_autoReconnectEnabled, attempts=$_reconnectAttempts');

    if (_autoReconnectEnabled &&
        _reconnectAttempts < _maxReconnectAttempts &&
        _lastDeviceId != null) {
      _reconnectAttempts++;
      print('=== [ILENS RECONNECT] Attempting reconnection $_reconnectAttempts/$_maxReconnectAttempts');
      developer.log('[ILENS] Attempting reconnection $_reconnectAttempts/$_maxReconnectAttempts', name: 'runvision');

      // Wait before reconnecting (exponential backoff)
      Future.delayed(Duration(seconds: 2 * _reconnectAttempts), () async {
        try {
          if (_autoReconnectEnabled && _lastDeviceId != null) {
            print('=== [ILENS RECONNECT] Reconnecting to $_lastDeviceId');
            await connect(_lastDeviceId!);
            print('=== [ILENS RECONNECT] Reconnection successful');
            developer.log('[ILENS] Reconnection successful', name: 'runvision');
          }
        } catch (e) {
          print('=== [ILENS RECONNECT] Reconnection failed: $e');
          developer.log('[ILENS] Reconnection failed: $e', name: 'runvision');
          _cleanup();
        }
      });
    } else {
      print('=== [ILENS RECONNECT] Max reconnection attempts reached or auto-reconnect disabled');
      developer.log('[ILENS] Max reconnection attempts reached', name: 'runvision');
      _cleanup();
    }
  }

  /// 리소스 정리
  void _cleanup() {
    _stopKeepAlive();
    _batteryPollTimer?.cancel();
    _batterySubscription?.cancel();
    _deviceStateSubscription?.cancel();

    _batteryPollTimer = null;
    _batterySubscription = null;
    _deviceStateSubscription = null;

    _connectedDevice = null;
    _configChar = null;
    _dataChar = null;
    _batteryChar = null;
    _currentTimeChar = null;
    _hibernationTimeChar = null;
    _brightnessChar = null;
    _screenOffTimeChar = null;
    _deviceStateChar = null;
    _universalSubChar = null;
  }
}

import 'dart:async';
import 'dart:developer' as developer;
import 'dart:typed_data';

import 'package:flutter_blue_plus/flutter_blue_plus.dart';
import 'package:runvision/core/error/failures.dart';
import 'package:runvision/features/ilens/domain/entities/ilens_types.dart';

/// iLens BLE 통신을 담당하는 Data Source
///
/// iLens Custom Protocol v1.0.10 구현
/// - Service UUID: c259c1bd-18d3-c348-b88d-5447aea1b615
/// - Config Characteristic: 00000001-c259-c1bd-18d3-c348b88d5447
/// - Data Characteristic: 00000002-c259-c1bd-18d3-c348b88d5447
/// - Status Characteristic: 00000003-c259-c1bd-18d3-c348b88d5447
class ILensBleDataSource {
  // ============================================================
  // STATE VARIABLES
  // ============================================================
  BluetoothDevice? _connectedDevice;
  BluetoothCharacteristic? _configChar;
  BluetoothCharacteristic? _dataChar;
  BluetoothCharacteristic? _batteryChar;
  BluetoothCharacteristic? _currentTimeChar;
  BluetoothCharacteristic? _hibernationTimeChar;
  BluetoothCharacteristic? _brightnessChar;
  BluetoothCharacteristic? _screenOffTimeChar; // Screen OFF Time (자동깨우기)
  BluetoothCharacteristic? _deviceStateChar; // Device state/config read characteristic
  BluetoothCharacteristic? _universalSubChar; // Universal Subscriptions characteristic (CRITICAL for initialization)

  final StreamController<ILensStatus> _statusController =
      StreamController<ILensStatus>.broadcast();

  StreamSubscription? _batterySubscription;
  Timer? _batteryPollTimer;  // Poll battery every 60 seconds
  StreamSubscription? _deviceStateSubscription;

  // Keep-alive mechanism
  Timer? _keepAliveTimer;
  String? _lastDeviceId;
