  /// iLens 기기 스캔
  ///
  /// [timeout] 스캔 타임아웃
  /// Returns: List<BluetoothDevice>
  Future<List<BluetoothDevice>> scanForDevices({
    Duration? timeout,
  }) async {
    try {
      developer.log('[ILENS] Starting scan for iLens devices', name: 'runvision');

      final devices = <BluetoothDevice>[];
      final scanCompleter = Completer<List<BluetoothDevice>>();

      // Start scanning
      final subscription = FlutterBluePlus.scanResults.listen((results) {
        print('=== [ILENS SCAN] Received ${results.length} scan results');
        for (final result in results) {
          final device = result.device;
          final deviceName = device.platformName.toLowerCase();

          print('=== [ILENS SCAN] Device: ${device.platformName} (${device.remoteId.str})');

          // iLens 기기는 advertisement data에 서비스 UUID를 포함하지 않으므로
          // 모든 기기를 표시하되, 이름에 "ilens"가 포함된 기기를 우선 표시
          // 실제 서비스 확인은 연결 후 service discovery에서 수행

          // Add unique devices only
          if (!devices.any((d) => d.remoteId.str == device.remoteId.str)) {
            devices.add(device);
            print('=== [ILENS SCAN] ✓ Added device: ${device.platformName} (${device.remoteId.str})');

            if (deviceName.contains('rlens')) {
              print('=== [ILENS SCAN] 🎯 Potential rLens device found by name');
              developer.log('[ILENS] Potential rLens device found: ${device.platformName} (${device.remoteId.str})', name: 'runvision');
            }
          }
        }
      });

      // Start scan
      await FlutterBluePlus.startScan(
        timeout: timeout ?? scanTimeout,
        // withServices: [Guid(ilensServiceUuid)],
      );

      // Wait for scan to complete
      await Future.delayed(timeout ?? scanTimeout);
      await FlutterBluePlus.stopScan();
      await subscription.cancel();

      // Sort devices: iLens/rLens devices first, then others
      devices.sort((a, b) {
        final aName = a.platformName.toLowerCase();
        final bName = b.platformName.toLowerCase();
        final aHasIlens = aName.contains('ilens') || aName.contains('rlens');
        final bHasIlens = bName.contains('ilens') || bName.contains('rlens');
        if (aHasIlens && !bHasIlens) return -1;
        if (!aHasIlens && bHasIlens) return 1;
        return a.platformName.compareTo(b.platformName);
      });

      developer.log('[ILENS] Scan completed. Found ${devices.length} devices', name: 'runvision');
      return devices;
    } catch (e, stackTrace) {
      developer.log('[ILENS] Scan failed: $e', name: 'runvision', stackTrace: stackTrace);
      throw Failure.unexpected(
        message: 'Failed to scan iLens devices: $e',
        stackTrace: stackTrace,
      );
    }
  }

  /// iLens 연결
  ///
  /// [deviceId] Bluetooth Device ID
  /// Returns: Future<void>
  /// Throws: Failure
  Future<void> connect(String deviceId) async {
    print('=== [ILENS CONNECT] Connecting to device: $deviceId');
    developer.log('[ILENS] Connecting to device: $deviceId', name: 'runvision');
    try {
      // First check if device is already connected
      final connectedDevices = FlutterBluePlus.connectedDevices;
      BluetoothDevice? device;

      // Try to find in already connected devices
      try {
        device = connectedDevices.firstWhere(
          (d) => d.remoteId.str == deviceId,
        );
        print('=== [ILENS CONNECT] Device already connected');
        developer.log('[ILENS] Device already connected', name: 'runvision');
      } catch (e) {
        // Not connected yet, create device from remoteId
        print('=== [ILENS CONNECT] Device not connected, creating BluetoothDevice from ID');
        developer.log('[ILENS] Device not connected, creating BluetoothDevice from ID', name: 'runvision');
        device = BluetoothDevice.fromId(deviceId);
        print('=== [ILENS CONNECT] Created device: ${device.platformName}');
        developer.log('[ILENS] Created device: ${device.platformName}', name: 'runvision');

        // Connect to device
        print('=== [ILENS CONNECT] Calling device.connect()...');
        developer.log('[ILENS] Connecting to device...', name: 'runvision');
        await device.connect(
          license: License.free,  // Free for individuals & small organizations (<50 employees)
          timeout: const Duration(seconds: 10),
        );
        print('=== [ILENS CONNECT] device.connect() completed');
        developer.log('[ILENS] Device.connect() completed', name: 'runvision');
      }

      _connectedDevice = device;
      _lastDeviceId = deviceId;
      _autoReconnectEnabled = true;
      _reconnectAttempts = 0;

      // Monitor connection state with auto-reconnect
      _deviceStateSubscription?.cancel();
      _deviceStateSubscription = device.connectionState.listen((state) {
        print('=== [ILENS CONNECT] Connection state changed: $state');
        developer.log('[ILENS] Connection state: $state', name: 'runvision');

        if (state == BluetoothConnectionState.disconnected) {
          print('=== [ILENS CONNECT] Device disconnected, attempting auto-reconnect');
          _stopKeepAlive();
          _handleDisconnection();
        } else if (state == BluetoothConnectionState.connected) {
          print('=== [ILENS CONNECT] Device connected');
          _reconnectAttempts = 0;
        }
      });

      // MTU 협상
      print('=== [ILENS CONNECT] Requesting MTU: $mtuSize');
      developer.log('[ILENS] Requesting MTU: $mtuSize', name: 'runvision');
      await _connectedDevice!.requestMtu(mtuSize);

      // Service Discovery
      print('=== [ILENS CONNECT] Starting service discovery');
      developer.log('[ILENS] Starting service discovery', name: 'runvision');
      await _discoverServices();

      // Battery 구독 (1초 폴링)
      await _subscribeToBattery();

      // CRITICAL: Send Universal Subscriptions initialization commands FIRST
      // This MUST happen before any other writes (time sync, config, settings)
      // iLens BLE V1.0.10.pdf Section 3.7: Universal Subscriptions
      // Official iLens app sends these 3 commands immediately after connection
      // This "warms up" the device and enables settings writes
      // CRITICAL: Must wait for NOTIFY responses, not just blindly wait 1200ms!
      if (_universalSubChar != null) {
        try {
          print('=== [ILENS INIT] Sending Universal Subscriptions initialization...');

          // Enable notifications and subscribe to receive responses (official app does this)
          if (_universalSubChar!.properties.notify) {
            try {
              // Subscribe to notification stream
              final notifyStream = _universalSubChar!.onValueReceived;
              int responsesReceived = 0;

              // Listen for responses (official app gets 3 NOTIFY responses)
              final responseCompleter = Completer<void>();
              final subscription = notifyStream.listen((value) {
                responsesReceived++;
                print('=== [ILENS INIT] ✓ Received NOTIFY response $responsesReceived: ${value.map((b) => '0x${b.toRadixString(16).padLeft(2, '0')}').join(' ')}');

                // Parse firmware version from first response ([0x10, 0x01] response)
                // Format: [0x10, 0x01, length, version_bytes..., ...]
                if (responsesReceived == 1 && value.length >= 3 && value[0] == 0x10 && value[1] == 0x01) {
                  final versionLength = value[2];
                  if (value.length >= 3 + versionLength) {
                    final versionBytes = value.sublist(3, 3 + versionLength);
                    _firmwareVersion = String.fromCharCodes(versionBytes);
                    print('=== [ILENS INIT] ✓ Firmware version: $_firmwareVersion');
                  }
                }

                if (responsesReceived >= 3) {
                  print('=== [ILENS INIT] ✓ All 3 initialization responses received');
                  if (!responseCompleter.isCompleted) {
                    responseCompleter.complete();
                  }
                }
              });

              // Enable notifications FIRST
              await _universalSubChar!.setNotifyValue(true);
              print('=== [ILENS INIT] ✓ Enabled notify for Universal Subscriptions');

              // Send initialization commands
              await _universalSubChar!.write([0x10, 0x01]);
              print('=== [ILENS INIT] ✓ Sent [0x10, 0x01] - Read version/language');

              await _universalSubChar!.write([0x10, 0x04]);
              print('=== [ILENS INIT] ✓ Sent [0x10, 0x04] - Read BT address');

              await _universalSubChar!.write([0x10, 0x03]);
              print('=== [ILENS INIT] ✓ Sent [0x10, 0x03] - Read translation setting');

              // Wait for all 3 NOTIFY responses (with timeout)
              print('=== [ILENS INIT] Waiting for device NOTIFY responses...');
              await responseCompleter.future.timeout(
                const Duration(seconds: 2),
                onTimeout: () {
                  print('=== [ILENS INIT] ⚠️ Timeout waiting for NOTIFY responses (got $responsesReceived/3)');
                },
              );

              // Cancel subscription after we're done
              await subscription.cancel();

              // CRITICAL: Disable notify after initialization to prevent interference
              // Some BLE stacks have issues with multiple notify-enabled characteristics
              try {
                await _universalSubChar!.setNotifyValue(false);
                print('=== [ILENS INIT] ✓ Disabled notify for Universal Subscriptions');
              } catch (e) {
                print('=== [ILENS INIT] ⚠️ Failed to disable notify: $e');
              }

              print('=== [ILENS INIT] ✓ Initialization complete, device ready for other writes');
            } catch (e) {
              print('=== [ILENS INIT] ⚠️ Failed to complete initialization: $e');
            }
          }
        } catch (e) {
          print('=== [ILENS INIT] ⚠️ Initialization failed (non-critical): $e');
          // Continue anyway - device might still work
        }
      } else {
        print('=== [ILENS INIT] ⚠️ Universal Subscriptions characteristic not found - skipping initialization');
        print('=== [ILENS INIT] ⚠️ Settings writes may fail with GATT_ERROR!');
      }

      // Time synchronization AFTER Universal Subscriptions init
      // Official iLens app sends time sync much later, but we need it for running metrics
      try {
        print('=== [ILENS CONNECT] Starting time synchronization...');

        // Wait for iLens boot sequence to complete
        print('=== [ILENS CONNECT] Waiting 1000ms for iLens boot sequence...');
        await Future.delayed(const Duration(milliseconds: 1000));

        // Send RTC sync (reason 0x03)
        final now = DateTime.now();
        print('=== [ILENS CONNECT] Sending RTC sync (reason 0x03) with time: ${now.toString()}');
        await _sendCurrentTimeWithTimestamp(now, reason: 0x03);

        print('=== [ILENS CONNECT] ✓ Time synchronization completed');
        developer.log('[ILENS] Time synchronization completed', name: 'runvision');
      } catch (e) {
        print('=== [ILENS CONNECT] ⚠️ Time synchronization failed (non-critical): $e');
        developer.log('[ILENS] Time synchronization failed (non-critical): $e', name: 'runvision');
        // Continue even if time sync fails
      }

      // Initialize characteristics by reading them once
      try {
        print('=== [ILENS CONNECT] Reading current settings from device...');

        if (_hibernationTimeChar != null) {
          final hibTime = await _hibernationTimeChar!.read();
          print('=== [ILENS CONNECT] ✓ Hibernation: $hibTime');
        }
        if (_brightnessChar != null) {
          final brightness = await _brightnessChar!.read();
          print('=== [ILENS CONNECT] ✓ Brightness: $brightness');
        }
      } catch (e) {
        print('=== [ILENS CONNECT] ⚠️ Settings read failed (non-critical): $e');
      }

      // NOTE: Time synchronization is now done in provider after Universal Subscriptions init
      // Official iLens app sends time sync AFTER initialization commands
      // We must follow the same order to avoid GATT errors

      // NOTE: Hibernation time is now managed by ILensSettingsNotifier
      // The saved user preference will be applied via applyToDevice() after connection
      // This allows users to control the screen timeout from the settings UI

      // NOTE: Keep-alive is no longer needed - 60s battery polling serves as keep-alive
      // _startKeepAlive();

      print('=== [ILENS CONNECT] Connection successful');
      developer.log('[ILENS] Connection successful, keep-alive started', name: 'runvision');
    } catch (e, stackTrace) {
      print('=== [ILENS CONNECT] Connection failed: $e');
      print('=== [ILENS CONNECT] Stack trace: $stackTrace');
      developer.log('[ILENS] Connection failed: $e', name: 'runvision', stackTrace: stackTrace);
      _cleanup();

      if (e is Failure) {
        rethrow;
      }

      throw Failure.unexpected(
        message: 'iLens connection failed: $e',
        stackTrace: stackTrace,
      );
    }
  }

  /// 연결 해제
  ///
  /// Returns: Future<void>
  Future<void> disconnect() async {
    print('=== [ILENS DISCONNECT] User initiated disconnect');
    developer.log('[ILENS] User initiated disconnect', name: 'runvision');

    _autoReconnectEnabled = false;
    _stopKeepAlive();

    if (_connectedDevice != null) {
      await _connectedDevice!.disconnect();
    }
    _cleanup();
  }

  /// UI 레이아웃 설정 전송
  ///
  /// [config] iLens UI 레이아웃 설정
  /// Returns: Future<void>
  /// Throws: Failure if write fails
  Future<void> sendConfig(ILensConfig config) async {
    if (_configChar == null) {
      throw const Failure.connection(message: 'Not connected to iLens');
    }

    developer.log('[ILENS] Sending config: layoutId=${config.layoutId}, metrics=${config.metrics.length}', name: 'runvision');
    final bytes = _encodeConfig(config);
    await _configChar!.write(bytes, withoutResponse: false);
    developer.log('[ILENS] Config sent successfully', name: 'runvision');
  }

  /// 현재 시간 전송 (iLens BLE V1.0.10 Section 3.3)
  ///
  /// iLens에 현재 시간을 전송하여 시계를 동기화합니다.
  ///
  /// [reason] Adjust Reason:
  ///   - 0x02: External Reference Time Update (Stage 1 - UI layer)
  ///   - 0x03: Change of Time Zone (Stage 2 - RTC sync trigger)
  ///
  /// Returns: Future<void>
  /// Throws: Failure if write fails or characteristic not available
  Future<void> sendCurrentTime({int reason = 0x03}) async {
    if (_currentTimeChar == null) {
      throw const Failure.connection(message: 'Current Time characteristic not available');
    }

    final now = DateTime.now();
    developer.log('[ILENS] Sending current time: ${now.toString()} (reason: 0x${reason.toRadixString(16).padLeft(2, '0')})', name: 'runvision');

    final bytes = _encodeCurrentTime(now, reason: reason);

    print('=== [ILENS TIME] ⚡ Writing to characteristic: ${_currentTimeChar!.uuid}');
    print('=== [ILENS TIME] ⚡ Characteristic properties: write=${_currentTimeChar!.properties.write}, writeWithoutResponse=${_currentTimeChar!.properties.writeWithoutResponse}');

    try {
      await _currentTimeChar!.write(bytes, withoutResponse: false);
      print('=== [ILENS TIME] ✓ Write operation completed without exception');

      // Read back to verify
      try {
        if (_currentTimeChar!.properties.read) {
          print('=== [ILENS TIME] 🔍 Reading back to verify...');
          final readBytes = await _currentTimeChar!.read();
          print('=== [ILENS TIME] 🔍 Read back: ${readBytes.map((b) => '0x${b.toRadixString(16).padLeft(2, '0')}').join(' ')}');
        } else {
          print('=== [ILENS TIME] ⚠️ Characteristic does not support read, cannot verify');
        }
      } catch (e) {
        print('=== [ILENS TIME] ⚠️ Read back failed: $e');
      }

      developer.log('[ILENS] Current time sent successfully', name: 'runvision');
      print('=== [ILENS TIME] ✓ Time synchronized: ${now.toString()}');
    } catch (e) {
      print('=== [ILENS TIME] ❌ Write failed: $e');
      rethrow;
    }
  }

  /// 지정된 타임스탬프로 현재 시간 전송 (2단계 동기화용 private 메서드)
  ///
  /// CRITICAL: 2단계 RTC 동기화를 위해 동일한 타임스탬프를 사용해야 함
  /// Stage 1 (reason 0x02)과 Stage 2 (reason 0x03)이 같은 시간을 사용해야
  /// iLens 펌웨어가 RTC를 올바르게 업데이트함
  ///
  /// [dateTime] 전송할 시간 (LOCAL 시간)
  /// [reason] Adjust Reason code
  ///   - 0x02: External Reference Time Update (Stage 1 - UI layer update)
  ///   - 0x03: Change of Time Zone (Stage 2 - RTC sync trigger)
  Future<void> _sendCurrentTimeWithTimestamp(DateTime dateTime, {int reason = 0x03}) async {
    if (_currentTimeChar == null) {
      throw const Failure.connection(message: 'Current Time characteristic not available');
    }

    developer.log('[ILENS] Sending time: ${dateTime.toString()} (reason: 0x${reason.toRadixString(16).padLeft(2, '0')})', name: 'runvision');

    final bytes = _encodeCurrentTime(dateTime, reason: reason);

    try {
      await _currentTimeChar!.write(bytes, withoutResponse: false);
      developer.log('[ILENS] Time sent successfully', name: 'runvision');
    } catch (e) {
      print('=== [ILENS TIME] ❌ Write failed: $e');
      rethrow;
    }
  }

  /// 메트릭 전송
  ///
  /// [metric] 전송할 메트릭
  /// Returns: Future<void>
  /// Throws: Failure if write fails
  Future<void> sendMetric(ILensMetric metric) async {
    if (_dataChar == null) {
      throw const Failure.connection(message: 'Not connected to iLens');
    }

    // iLens characteristic doesn't support WRITE_NO_RESPONSE
    // Use withoutResponse: false instead
    final bytes = _encodeMetric(metric);
    await _dataChar!.write(bytes, withoutResponse: false);
  }

  /// Set hibernation time (screen sleep timeout)
  ///
  /// [seconds] Hibernation time in seconds (UINT16, 0-65535)
  ///           - 65535 (0xFFFF): "Never" - screen stays on during workout
  ///           - 3: Short timeout after workout ends (UX signal)
  ///
  /// iLens BLE V1.0.10.pdf Section 3.5: Sleep time setting
  /// Format: 2 bytes, little-endian
  ///
  /// Returns: Future<void>
  /// Throws: Failure if write fails or characteristic not available
  Future<void> setHibernationTime(int seconds) async {
    if (_hibernationTimeChar == null) {
      throw const Failure.connection(
        message: 'Hibernation Time characteristic not available',
      );
    }

    if (seconds < 0 || seconds > 65535) {
      throw Failure.unexpected(
        message: 'Hibernation time must be 0-65535 seconds (got: $seconds)',
      );
    }

    try {
      // Encode as UINT16 little-endian (2 bytes)
      final buffer = Uint8List(2);
      final byteData = ByteData.view(buffer.buffer);
      byteData.setUint16(0, seconds, Endian.little);

      print('=== [ILENS HIBERNATION] Setting hibernation time: ${seconds}s');
      print('=== [ILENS HIBERNATION] Bytes: ${buffer.map((b) => '0x${b.toRadixString(16).padLeft(2, '0')}').join(' ')}');
      developer.log('[ILENS] Setting hibernation time: ${seconds}s', name: 'runvision');

      await _hibernationTimeChar!.write(buffer.toList(), withoutResponse: false);

      print('=== [ILENS HIBERNATION] ✓ Hibernation time set successfully');
      developer.log('[ILENS] Hibernation time set successfully', name: 'runvision');
    } catch (e, stackTrace) {
      print('=== [ILENS HIBERNATION] ❌ Write failed: $e');
      developer.log('[ILENS] Hibernation time write failed: $e', name: 'runvision', stackTrace: stackTrace);
      throw Failure.unexpected(
        message: 'Failed to set hibernation time: $e',
        stackTrace: stackTrace,
      );
    }
  }

  /// Get current hibernation time from device
  ///
  /// Returns: Future<int> hibernation time in seconds (0-65535)
  /// Throws: Failure if read fails
  Future<int> getHibernationTime() async {
    if (_hibernationTimeChar == null) {
      throw const Failure.connection(
        message: 'Hibernation Time characteristic not available',
      );
    }

    try {
      final bytes = await _hibernationTimeChar!.read();
      if (bytes.length >= 2) {
        final byteData = ByteData.view(Uint8List.fromList(bytes).buffer);
        final seconds = byteData.getUint16(0, Endian.little);
        print('=== [ILENS HIBERNATION] Read hibernation time: ${seconds}s');
        developer.log('[ILENS] Read hibernation time: ${seconds}s', name: 'runvision');
        return seconds;
      }
      return 65535; // Default: Always on
    } catch (e) {
      print('=== [ILENS HIBERNATION] ❌ Read failed: $e');
      developer.log('[ILENS] Hibernation time read failed: $e', name: 'runvision');
      return 65535; // Default
    }
  }

  /// Set screen OFF time (자동깨우기)
  ///
  /// [seconds] Screen OFF time in seconds
  ///   - 10-900: Auto-off after specified seconds
  ///   - 65535: Touch mode (only turns off on button press)
  ///
  /// rLens BLE Protocol v1.0.1: Screen OFF Time
  /// Format: 2 bytes UINT16, little-endian
  ///
  /// Returns: Future<void>
  /// Throws: Failure if write fails or characteristic not available
  Future<void> setScreenOffTime(int seconds) async {
    if (_screenOffTimeChar == null) {
      throw const Failure.connection(
        message: 'Screen OFF Time characteristic not available',
      );
    }

    try {
      // Encode as UINT16 little-endian (2 bytes)
      final buffer = Uint8List(2);
      final byteData = ByteData.view(buffer.buffer);
      byteData.setUint16(0, seconds, Endian.little);

      final displayValue = seconds == 65535 ? 'Touch Mode' : '${seconds}s';
      print('=== [ILENS SCREEN_OFF] Setting screen OFF time: $displayValue');
      print('=== [ILENS SCREEN_OFF] Bytes: ${buffer.map((b) => '0x${b.toRadixString(16).padLeft(2, '0')}').join(' ')}');
      developer.log('[ILENS] Setting screen OFF time: $displayValue', name: 'runvision');

      await _screenOffTimeChar!.write(buffer.toList(), withoutResponse: false);

      print('=== [ILENS SCREEN_OFF] ✓ Screen OFF time set successfully');
      developer.log('[ILENS] Screen OFF time set successfully', name: 'runvision');
    } catch (e, stackTrace) {
      print('=== [ILENS SCREEN_OFF] ❌ Write failed: $e');
      developer.log('[ILENS] Screen OFF time write failed: $e', name: 'runvision', stackTrace: stackTrace);
      throw Failure.unexpected(
        message: 'Failed to set screen OFF time: $e',
        stackTrace: stackTrace,
      );
    }
  }

  /// Get current screen OFF time from device
  ///
  /// Returns: Future<int> screen OFF time in seconds
  ///   - 10-900: Auto-off after specified seconds
  ///   - 65535: Touch mode
  /// Throws: Failure if read fails
  Future<int> getScreenOffTime() async {
    if (_screenOffTimeChar == null) {
      throw const Failure.connection(
        message: 'Screen OFF Time characteristic not available',
      );
    }

    try {
      final bytes = await _screenOffTimeChar!.read();
      if (bytes.length >= 2) {
        final byteData = ByteData.view(Uint8List.fromList(bytes).buffer);
        final seconds = byteData.getUint16(0, Endian.little);
        final displayValue = seconds == 65535 ? 'Touch Mode' : '${seconds}s';
        print('=== [ILENS SCREEN_OFF] Read screen OFF time: $displayValue');
        developer.log('[ILENS] Read screen OFF time: $displayValue', name: 'runvision');
        return seconds;
      }
      return 60; // Default: 1 minute
    } catch (e) {
      print('=== [ILENS SCREEN_OFF] ❌ Read failed: $e');
      developer.log('[ILENS] Screen OFF time read failed: $e', name: 'runvision');
      return 60; // Default
    }
  }

  /// Set display brightness
  ///
  /// [percent] Brightness percentage (0-100)
  ///
  /// iLens BLE V1.0.10.pdf Section 3.4: Brightness settings
  /// Format: 4 bytes UINT32, little-endian
  ///
  /// Returns: Future<void>
  /// Throws: Failure if write fails or characteristic not available
  Future<void> setBrightness(int percent) async {
    if (_brightnessChar == null) {
      throw const Failure.connection(
        message: 'Brightness characteristic not available',
      );
    }

    if (percent < 0 || percent > 100) {
      throw Failure.unexpected(
        message: 'Brightness must be 0-100% (got: $percent)',
      );
    }

    try {
      // Encode as UINT32 little-endian (4 bytes)
      final buffer = Uint8List(4);
      final byteData = ByteData.view(buffer.buffer);
      byteData.setUint32(0, percent, Endian.little);

      print('=== [ILENS BRIGHTNESS] Setting brightness: $percent%');
      print('=== [ILENS BRIGHTNESS] Bytes: ${buffer.map((b) => '0x${b.toRadixString(16).padLeft(2, '0')}').join(' ')}');
      developer.log('[ILENS] Setting brightness: $percent%', name: 'runvision');

      await _brightnessChar!.write(buffer.toList(), withoutResponse: false);

      print('=== [ILENS BRIGHTNESS] ✓ Brightness set successfully');
      developer.log('[ILENS] Brightness set successfully', name: 'runvision');
    } catch (e, stackTrace) {
      print('=== [ILENS BRIGHTNESS] ❌ Write failed: $e');
      developer.log('[ILENS] Brightness write failed: $e', name: 'runvision', stackTrace: stackTrace);
      throw Failure.unexpected(
        message: 'Failed to set brightness: $e',
        stackTrace: stackTrace,
      );
    }
  }

  /// Get current brightness from device
  ///
  /// Returns: Future<int> brightness percentage (0-100)
  /// Throws: Failure if read fails
  Future<int> getBrightness() async {
    if (_brightnessChar == null) {
      throw const Failure.connection(
        message: 'Brightness characteristic not available',
      );
    }

    try {
      final bytes = await _brightnessChar!.read();
      if (bytes.length >= 4) {
        final byteData = ByteData.view(Uint8List.fromList(bytes).buffer);
        final brightness = byteData.getUint32(0, Endian.little);
        print('=== [ILENS BRIGHTNESS] Read brightness: $brightness%');
        developer.log('[ILENS] Read brightness: $brightness%', name: 'runvision');
        return brightness.clamp(0, 100);
      }
      return 50; // Default if read fails
    } catch (e) {
      print('=== [ILENS BRIGHTNESS] ❌ Read failed: $e');
      developer.log('[ILENS] Brightness read failed: $e', name: 'runvision');
      return 50; // Default
    }
  }

  /// Check if brightness control is available
  bool get isBrightnessAvailable => _brightnessChar != null;

  /// Enable or disable screen activity (battery polling & keep-alive)
  ///
  /// When disabled, no READ operations are performed, allowing
  /// hibernation timer to work correctly.
  ///
  /// [enabled] true to enable polling, false to disable
  void setScreenActivityEnabled(bool enabled) {
    _screenActivityEnabled = enabled;
    print('=== [ILENS] Screen activity ${enabled ? "ENABLED" : "DISABLED"}');

    if (enabled) {
      // Resume polling if connected
      if (_connectedDevice != null && _batteryChar != null) {
        _subscribeToBattery();
        _startKeepAlive();
      }
    } else {
      // Stop all polling to allow hibernation
      _batteryPollTimer?.cancel();
      _batteryPollTimer = null;
      _stopKeepAlive();
    }
  }

  /// Check if screen activity (polling) is enabled
  bool get isScreenActivityEnabled => _screenActivityEnabled;

  /// iLens 상태 스트림
