  /// Queue a BLE write operation to prevent simultaneous writes
  Future<void> _queueWrite(Future<void> Function() writeOperation) async {
    final completer = Completer<void>();

    _writeQueue.add(() async {
      try {
        await writeOperation();
        completer.complete();
      } catch (e) {
        completer.completeError(e);
      }
    });

    _processWriteQueue();
    return completer.future;
  }

  /// Process write queue sequentially
  Future<void> _processWriteQueue() async {
    if (_isProcessingQueue || _writeQueue.isEmpty) return;

    _isProcessingQueue = true;
    print('=== [ILENS QUEUE] Starting queue processing (${_writeQueue.length} items)');

    while (_writeQueue.isNotEmpty) {
      final operation = _writeQueue.removeAt(0);
      try {
        await operation();
        print('=== [ILENS QUEUE] ✓ Operation completed');
      } catch (e) {
        print('=== [ILENS QUEUE] ⚠️ Operation failed: $e');
        // Continue processing queue even if one operation fails
      }
    }

    _isProcessingQueue = false;
    print('=== [ILENS QUEUE] Queue processing complete');
  }

  Future<void> _discoverServices() async {
    print('=== [ILENS DISCOVER] Calling discoverServices()...');
    final services = await _connectedDevice!.discoverServices();
    print('=== [ILENS DISCOVER] Discovered ${services.length} services');
    developer.log('[ILENS] Discovered ${services.length} services', name: 'runvision');

    for (var service in services) {
      print('=== [ILENS DISCOVER]   Service: ${service.uuid.str}');
      developer.log('[ILENS]   Service: ${service.uuid.str}', name: 'runvision');
      for (var char in service.characteristics) {
        print('=== [ILENS DISCOVER]     Char: ${char.uuid.str}');
        developer.log('[ILENS]     Char: ${char.uuid.str}', name: 'runvision');
      }
    }

    print('=== [ILENS DISCOVER] Searching for iLens Service UUID: $ilensServiceUuid');
    // Try to find iLens service (case insensitive, with or without dashes)
    final ilensService = services.firstWhere(
      (s) {
        final serviceUuid = s.uuid.str.toLowerCase().replaceAll('-', '');
        final targetUuid = ilensServiceUuid.toLowerCase().replaceAll('-', '');
        print('=== [ILENS DISCOVER] Comparing: ${s.uuid.str} (normalized: $serviceUuid) with target: $ilensServiceUuid (normalized: $targetUuid)');
        developer.log('[ILENS] Comparing service ${s.uuid.str} with target $ilensServiceUuid', name: 'runvision');
        return serviceUuid == targetUuid;
      },
      orElse: () {
        print('=== [ILENS DISCOVER] ERROR: iLens Service not found! Available services:');
        developer.log('[ILENS] ERROR: iLens Service not found! Available services:', name: 'runvision');
        for (var s in services) {
          print('=== [ILENS DISCOVER]   - ${s.uuid.str}');
          developer.log('[ILENS]   - ${s.uuid.str}', name: 'runvision');
        }
        throw const Failure.connection(
          message: 'iLens Service not found',
        );
      },
    );
    print('=== [ILENS DISCOVER] Found iLens Service: ${ilensService.uuid.str}');
    developer.log('[ILENS] Found iLens Service: ${ilensService.uuid.str}', name: 'runvision');

    // iLens uses a single characteristic for all communication
    final mainChar = ilensService.characteristics.firstWhere(
      (c) {
        final charUuid = c.uuid.str.toLowerCase().replaceAll('-', '');
        final targetUuid = configCharUuid.toLowerCase().replaceAll('-', '');
        return charUuid == targetUuid;
      },
      orElse: () => throw const Failure.connection(
        message: 'Main Characteristic (c259c1bd-18d3-c348-b88d-5447aea1b615) not found',
      ),
    );

    // Use the same characteristic for config and data operations
    _configChar = mainChar;
    _dataChar = mainChar;
    print('=== [ILENS DISCOVER] ✓ Found Main Characteristic: ${mainChar.uuid.str}');
    developer.log('[ILENS] Found Main Characteristic: ${mainChar.uuid.str}', name: 'runvision');

    // Find battery characteristic (separate from main char)
    // Battery is in Device configuration services (58211C97-482A-2808-2D3E-228405F1E749)
    final batteryService = services.firstWhere(
      (s) {
        final serviceUuid = s.uuid.str.toLowerCase().replaceAll('-', '');
        const targetUuid = '58211c97482a28082d3e228405f1e749';
        return serviceUuid == targetUuid;
      },
      orElse: () {
        print('=== [ILENS DISCOVER] Battery service not found, battery monitoring disabled');
        developer.log('[ILENS] Battery service not found, battery monitoring disabled', name: 'runvision');
        return null as BluetoothService;
      },
    );

    try {
      _batteryChar = batteryService.characteristics.firstWhere(
        (c) {
          final charUuid = c.uuid.str.toLowerCase().replaceAll('-', '');
          final targetUuid = batteryCharUuid.toLowerCase().replaceAll('-', '');
          return charUuid == targetUuid;
        },
      );
      print('=== [ILENS DISCOVER] ✓ Found Battery Characteristic: ${_batteryChar!.uuid.str}');
      developer.log('[ILENS] Found Battery Characteristic: ${_batteryChar!.uuid.str}', name: 'runvision');
    } catch (e) {
      print('=== [ILENS DISCOVER] Battery characteristic not found in service');
      developer.log('[ILENS] Battery characteristic not found in service', name: 'runvision');
    }

    // Find Current Time characteristic in the same Device Configuration Service
    try {
      print('=== [ILENS DISCOVER] Looking for Current Time characteristic: $currentTimeCharUuid');
      print('=== [ILENS DISCOVER] Available characteristics in Device Configuration Service:');
      for (final char in batteryService.characteristics) {
        print('  - ${char.uuid.str} (write: ${char.properties.write}, read: ${char.properties.read})');
      }

      _currentTimeChar = batteryService.characteristics.firstWhere(
        (c) {
          final charUuid = c.uuid.str.toLowerCase().replaceAll('-', '');
          final targetUuid = currentTimeCharUuid.toLowerCase().replaceAll('-', '');
          print('=== [ILENS DISCOVER] Comparing: $charUuid vs $targetUuid');
          return charUuid == targetUuid;
        },
      );
      print('=== [ILENS DISCOVER] ✓ Found Current Time Characteristic: ${_currentTimeChar!.uuid.str}');
      print('=== [ILENS DISCOVER] ✓ Properties: write=${_currentTimeChar!.properties.write}, read=${_currentTimeChar!.properties.read}');
      developer.log('[ILENS] Found Current Time Characteristic: ${_currentTimeChar!.uuid.str}', name: 'runvision');
    } catch (e) {
      print('=== [ILENS DISCOVER] ❌ Current Time characteristic not found in service: $e');
