      print('=== [ILENS DISCOVER] ✓ Found Screen OFF Time Characteristic: ${_screenOffTimeChar!.uuid.str}');
      print('=== [ILENS DISCOVER] ✓ Properties: write=${_screenOffTimeChar!.properties.write}, read=${_screenOffTimeChar!.properties.read}');
      developer.log('[ILENS] Found Screen OFF Time Characteristic: ${_screenOffTimeChar!.uuid.str}', name: 'runvision');
    } catch (e) {
      print('=== [ILENS DISCOVER] ⚠️ Screen OFF Time characteristic not found in service: $e');
      developer.log('[ILENS] Screen OFF Time characteristic not found in service (may not be supported by this device)', name: 'runvision');
    }

    // Find Device State characteristic (CRITICAL: Must be read before writing settings!)
    // This characteristic was discovered from iLens official app behavior
    try {
      print('=== [ILENS DISCOVER] Looking for Device State characteristic: $deviceStateCharUuid');
      _deviceStateChar = batteryService.characteristics.firstWhere(
