import 'dart:async';
import 'dart:developer' as developer;
import 'dart:typed_data';

import 'package:flutter_blue_plus/flutter_blue_plus.dart';
import 'package:runvision/core/error/failures.dart';
import 'package:runvision/features/ilens/domain/entities/ilens_types.dart';

/// iLens BLE 통신을 담당하는 Data Source
///
/// iLens Custom Protocol v1.0.10 구현
/// - Service UUID: c259c1bd-18d3-c348-b88d-5447aea1b615
/// - Config Characteristic: 00000001-c259-c1bd-18d3-c348b88d5447
/// - Data Characteristic: 00000002-c259-c1bd-18d3-c348b88d5447
/// - Status Characteristic: 00000003-c259-c1bd-18d3-c348b88d5447
class ILensBleDataSource {
  // ============================================================
  // STATE VARIABLES
  // ============================================================
  BluetoothDevice? _connectedDevice;
  BluetoothCharacteristic? _configChar;
  BluetoothCharacteristic? _dataChar;
  BluetoothCharacteristic? _batteryChar;
  BluetoothCharacteristic? _currentTimeChar;
  BluetoothCharacteristic? _hibernationTimeChar;
  BluetoothCharacteristic? _brightnessChar;
  BluetoothCharacteristic? _screenOffTimeChar; // Screen OFF Time (자동깨우기)
  BluetoothCharacteristic? _deviceStateChar; // Device state/config read characteristic
  BluetoothCharacteristic? _universalSubChar; // Universal Subscriptions characteristic (CRITICAL for initialization)

  final StreamController<ILensStatus> _statusController =
      StreamController<ILensStatus>.broadcast();

  StreamSubscription? _batterySubscription;
  Timer? _batteryPollTimer;  // Poll battery every 60 seconds
  StreamSubscription? _deviceStateSubscription;

  // Keep-alive mechanism
  Timer? _keepAliveTimer;
  String? _lastDeviceId;
  bool _autoReconnectEnabled = false;
  int _reconnectAttempts = 0;
  static const int _maxReconnectAttempts = 3;
  static const Duration _keepAliveInterval = Duration(seconds: 5);

  // Screen activity control - disable polling during hibernation test
  bool _screenActivityEnabled = true;

  // Firmware version (parsed from Universal Subscriptions init response)
  String? _firmwareVersion;
  String? get firmwareVersion => _firmwareVersion;

  // Cached battery level for status re-emit after firmware version is known
  int _lastBatteryLevel = 0;

  // Write queue to prevent simultaneous BLE writes
  final List<Future<void> Function()> _writeQueue = [];
  bool _isProcessingQueue = false;

  // ============================================================
  // CONSTANTS (iLens Custom Protocol - Actual Device UUIDs)
  // ============================================================
  // Real iLens Service UUID discovered from device
  static const String ilensServiceUuid = '4b329cf2-3816-498c-8453-ee8798502a08';

  // Actual Characteristics discovered from iLens-3265 device
  // Available Characteristics in Service 4b329cf2-3816-498c-8453-ee8798502a08:
  //   - 0eb521eb-127d-4a9f-b4a2-37241250542d
  //   - 0d240db6-0e0c-43fe-a250-8244b3989faa
  //   - c259c1bd-18d3-c348-b88d-5447aea1b615  <- Main characteristic (formerly Service UUID!)
  //   - 8562cfa2-ce05-f27b-b745-0395a22dd9a3
  //   - 14a45127-f4e6-4cc5-a429-ca2bf56def84
  //   - 71c4264b-5fef-9fe1-cf6a-19739bfd9828
  //   - 44a6e10d-1b43-5eb2-bf9c-2577ba2c1a86
  // iLens BLE V1.0.10.pdf Section 4.3: Exercise data
  static const String configCharUuid = 'c259c1bd-18d3-c348-b88d-5447aea1b615';  // UI sorting + Exercise data
  static const String dataCharUuid = 'c259c1bd-18d3-c348-b88d-5447aea1b615';    // Same as config (write-only)

  // iLens BLE V1.0.10.pdf Section 3.2: Battery Level (READ, NOTIFY)
  static const String batteryCharUuid = '33bd4a32-f763-0391-2820-55610f999aef';

  // iLens BLE V1.0.10.pdf Section 3: Device configuration services
  static const String deviceConfigServiceUuid = '58211c97-482a-2808-2d3e-228405f1e749';
  // iLens BLE V1.0.10.pdf Section 3.3: Current Time (READ, WRITE)
