  // UUID: c1329ce5-b463-31a5-8b78-bd220c1480cd
  // Type: WRITE (requests), NOTIFY (responses)
  // Description: Universal subscription characteristic for device initialization
  // CRITICAL: Official iLens app writes 3 initialization commands after connection:
  //   - [0x10, 0x01]: Read resource package version and language
  //   - [0x10, 0x04]: Read traditional Bluetooth address
  //   - [0x10, 0x03]: Read translation display setting
  // These MUST be sent before any settings writes, otherwise GATT_ERROR occurs!
  static const String universalSubCharUuid = 'c1329ce5-b463-31a5-8b78-bd220c1480cd';

