import 'dart:async';

import 'package:flutter/material.dart';
import 'package:flutter/services.dart';
import 'package:flutter_blue_plus/flutter_blue_plus.dart';
import 'package:flutter_riverpod/flutter_riverpod.dart';
import 'package:package_info_plus/package_info_plus.dart';
import 'package:runvision/features/ilens/presentation/providers/ilens_providers.dart';
import 'package:runvision/features/ilens/presentation/widgets/ilens_settings_card.dart';
import 'package:shared_preferences/shared_preferences.dart';

/// iLens 연결 및 설정 페이지
class ILensPage extends ConsumerStatefulWidget {
  const ILensPage({super.key});

  @override
  ConsumerState<ILensPage> createState() => _ILensPageState();
}

class _ILensPageState extends ConsumerState<ILensPage> with WidgetsBindingObserver {
  static const String _keyILensDeviceId = 'last_ilens_device_id';
  static const String _keyILensDeviceName = 'last_ilens_device_name';

  String _appVersion = '...'; // 앱 버전 (pubspec.yaml에서 자동 로드)

  @override
  void initState() {
    super.initState();
    WidgetsBinding.instance.addObserver(this);
    _loadAppVersion();
    WidgetsBinding.instance.addPostFrameCallback((_) {
      _tryAutoReconnect();
    });
  }

  /// pubspec.yaml에서 앱 버전 자동 로드
  Future<void> _loadAppVersion() async {
    final packageInfo = await PackageInfo.fromPlatform();
    setState(() {
      _appVersion = packageInfo.version;
    });
  }

  @override
  void dispose() {
    WidgetsBinding.instance.removeObserver(this);
    super.dispose();
  }

  @override
  void didChangeAppLifecycleState(AppLifecycleState state) {
    super.didChangeAppLifecycleState(state);
    if (state == AppLifecycleState.detached || state == AppLifecycleState.paused) {
      _disconnectDevice();
    }
  }

  Future<void> _disconnectDevice() async {
    try {
      final ilensConnectionState = ref.read(ilensConnectionStateProvider);
      if (ilensConnectionState) {
        await ref.read(ilensScannedDevicesProvider.notifier).disconnect();
      }
    } catch (e) {
      print('[ILENS PAGE] Error disconnecting: $e');
    }
  }

  Future<void> _tryAutoReconnect() async {
    try {
      final prefs = await SharedPreferences.getInstance();
      final ilensDeviceId = prefs.getString(_keyILensDeviceId);
      final ilensDeviceName = prefs.getString(_keyILensDeviceName);

      // 1. 저장된 기기 정보가 있으면 먼저 직접 연결 시도 (스캔 없이)
      if (ilensDeviceId != null) {
        print('[AUTO-CONNECT] Trying saved device: $ilensDeviceName ($ilensDeviceId)');

        // Show connecting state (not scanning)
        ref.read(ilensScanningStateProvider.notifier).state = true;

        // Try direct connection without scanning (BLE can connect to known MAC address)
        try {
          print('[AUTO-CONNECT] Trying direct connection without scan...');
          await ref.read(ilensScannedDevicesProvider.notifier).connect(ilensDeviceId);
          print('[AUTO-CONNECT] ✓ Connected to saved device');
          if (ilensDeviceName != null) {
            ref.read(ilensConnectedDeviceNameProvider.notifier).state = ilensDeviceName;
          }
          // Read device settings after connection
          await ref.read(ilensSettingsProvider.notifier).readFromDevice();
          return; // 연결 성공하면 종료
        } catch (e) {
          print('[AUTO-CONNECT] Direct connection failed: $e');
          // Don't stop scanning state - will continue to scan
        }
      }

      // 2. 자동 스캔 시작 (마지막 수단 또는 저장된 기기가 없을 때)
      print('[AUTO-CONNECT] Starting scan...');
      await _autoScanAndConnect();
    } catch (e) {
      print('[AUTO-CONNECT] Error: $e');
      ref.read(ilensScanningStateProvider.notifier).state = false;
    }
  }

  /// 자동 스캔 후 iLens 기기 발견 시 즉시 연결
  Future<void> _autoScanAndConnect() async {
    print('[AUTO-SCAN] Starting real-time scan for iLens...');
    ref.read(ilensScanningStateProvider.notifier).state = true;

    final dataSource = ref.read(ilensDataSourceProvider);
    StreamSubscription<List<ScanResult>>? subscription;
    bool connectionInProgress = false;

    try {
      final scannedDevices = <BluetoothDevice>[];

      // Listen to scan results in real-time
      subscription = FlutterBluePlus.scanResults.listen((results) async {
        // Skip if already connecting
        if (connectionInProgress) return;

        for (final result in results) {
          final device = result.device;
          final deviceName = device.platformName.toLowerCase();

          // Add to scanned devices list (unique)
          if (!scannedDevices.any((d) => d.remoteId.str == device.remoteId.str)) {
            scannedDevices.add(device);
            ref.read(ilensScannedDevicesProvider.notifier).state = List.from(scannedDevices);
          }

          // If rLens found and not already connecting, connect immediately
          if (deviceName.contains('rlens') && !connectionInProgress) {
            connectionInProgress = true;
            final name = device.platformName.isEmpty
                ? device.remoteId.str
                : device.platformName;
            print('[AUTO-SCAN] 🎯 iLens found! Connecting immediately to: $name');

            // Stop scan immediately
            try {
              await FlutterBluePlus.stopScan();
              print('[AUTO-SCAN] ✓ Scan stopped');
            } catch (e) {
              print('[AUTO-SCAN] Stop scan error (non-critical): $e');
            }

            // Cancel subscription
            try {
              await subscription?.cancel();
              print('[AUTO-SCAN] ✓ Subscription cancelled');
            } catch (e) {
              print('[AUTO-SCAN] Cancel subscription error (non-critical): $e');
            }

            // Auto-connect
            try {
              await ref.read(ilensScannedDevicesProvider.notifier).connect(device.remoteId.str);
              await _saveILensDevice(device.remoteId.str, name);
              ref.read(ilensConnectedDeviceNameProvider.notifier).state = name;
              print('[AUTO-SCAN] ✓ Auto-connected to $name');
            } catch (e) {
              print('[AUTO-SCAN] ❌ Auto-connect failed: $e');
              ref.read(ilensScanningStateProvider.notifier).state = false;
            }
            return; // Exit early after connection attempt
          }
        }
      });

      // Start scan with 5 second timeout
      await FlutterBluePlus.startScan(timeout: const Duration(seconds: 5));

      // Wait for scan to complete (if iLens not found)
      await Future.delayed(const Duration(seconds: 5));

      if (!connectionInProgress) {
        print('[AUTO-SCAN] Scan completed - no iLens device found');
      }
    } finally {
      try {
        await FlutterBluePlus.stopScan();
      } catch (e) {
        print('[AUTO-SCAN] Final stop scan error: $e');
      }
      try {
        await subscription?.cancel();
      } catch (e) {
        print('[AUTO-SCAN] Final cancel subscription error: $e');
      }
      if (!connectionInProgress) {
        ref.read(ilensScanningStateProvider.notifier).state = false;
      }
    }
  }

  Future<void> _saveILensDevice(String deviceId, String deviceName) async {
    try {
      final prefs = await SharedPreferences.getInstance();
      await prefs.setString(_keyILensDeviceId, deviceId);
      await prefs.setString(_keyILensDeviceName, deviceName);
    } catch (e) {
      print('[SAVE] Failed to save iLens device: $e');
    }
  }

  @override
  Widget build(BuildContext context) {
    final ilensStatus = ref.watch(ilensStatusProvider);
    final ilensConnectionState = ref.watch(ilensConnectionStateProvider);
    final ilensConnectedDevice = ref.watch(ilensConnectedDeviceProvider);
    final ilensConnectedDeviceName = ref.watch(ilensConnectedDeviceNameProvider);
    final ilensScannedDevices = ref.watch(ilensScannedDevicesProvider);
    final ilensScannedDevicesNotifier = ref.read(ilensScannedDevicesProvider.notifier);
    final ilensScanningState = ref.watch(ilensScanningStateProvider);

    return WillPopScope(
      onWillPop: () async {
        final shouldExit = await showDialog<bool>(
          context: context,
          builder: (context) => AlertDialog(
            title: const Text('앱 종료'),
            content: const Text('앱을 종료하시겠습니까?'),
            actions: [
              TextButton(
                onPressed: () => Navigator.of(context).pop(false),
                child: const Text('취소'),
              ),
              TextButton(
                onPressed: () => Navigator.of(context).pop(true),
                child: const Text('종료'),
              ),
            ],
          ),
        );

        if (shouldExit == true) {
          _disconnectDevice();
          SystemNavigator.pop();
          return true;
        }
        return false;
      },
      child: Scaffold(
        appBar: AppBar(
          title: Text('RunVision ($_appVersion)'),
          backgroundColor: Theme.of(context).colorScheme.inversePrimary,
        ),
        body: SafeArea(
          top: false, // AppBar handles top inset
          child: ilensConnectionState
              ? _buildConnectedUI(
                  ilensStatus,
                  ilensConnectedDevice,
                  ilensConnectedDeviceName,
                )
              : _buildDisconnectedUI(
                  ilensScannedDevices,
                  ilensScannedDevicesNotifier,
                  ilensScanningState,
                ),
        ),
      ),
    );
  }

  Widget _buildConnectedUI(
    AsyncValue ilensStatus,
    dynamic ilensConnectedDevice,
    String? ilensConnectedDeviceName,
  ) {
    final deviceName = ilensConnectedDeviceName ??
        (ilensConnectedDevice?.platformName.isEmpty == true
            ? ilensConnectedDevice?.remoteId.str.substring(0, 8) ?? 'RunVision'
            : ilensConnectedDevice?.platformName ?? 'RunVision');

    return Padding(
      padding: const EdgeInsets.all(16),
      child: Column(
        children: [
          // 연결 상태 카드 (컴팩트)
          Card(
            elevation: 4,
            shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(16)),
            child: Padding(
              padding: const EdgeInsets.all(16),
              child: Row(
                children: [
                  // 연결 아이콘
                  Container(
                    width: 56,
                    height: 56,
                    decoration: BoxDecoration(
                      shape: BoxShape.circle,
                      color: Colors.green.shade50,
                    ),
                    child: Icon(
                      Icons.bluetooth_connected,
                      size: 28,
                      color: Colors.green.shade600,
                    ),
                  ),
                  const SizedBox(width: 16),
                  // 기기 정보
                  Expanded(
                    child: Column(
                      crossAxisAlignment: CrossAxisAlignment.start,
                      children: [
                        Text(
                          deviceName,
                          style: const TextStyle(
                            fontSize: 18,
                            fontWeight: FontWeight.bold,
                          ),
                        ),
                        // 연결 상태 + 배터리
                        Row(
                          children: [
                            Icon(Icons.check_circle, size: 14, color: Colors.green.shade600),
                            const SizedBox(width: 4),
                            Text(
                              '연결됨',
                              style: TextStyle(
                                fontSize: 13,
                                color: Colors.green.shade600,
                                fontWeight: FontWeight.w500,
                              ),
                            ),
                            ilensStatus.when(
                              data: (status) => Row(
                                children: [
                                  const SizedBox(width: 8),
                                  Icon(Icons.battery_full, size: 14, color: Colors.green.shade600),
                                  const SizedBox(width: 2),
                                  Text(
                                    '${status.batteryLevel}%',
                                    style: TextStyle(
                                      fontSize: 13,
                                      color: Colors.green.shade600,
                                      fontWeight: FontWeight.w500,
                                    ),
                                  ),
                                  if (status.firmwareVersion != null) ...[
                                    const SizedBox(width: 8),
                                    Text(
                                      'firm:v${status.firmwareVersion}',
                                      style: TextStyle(
                                        fontSize: 13,
                                        color: Colors.green.shade600,
                                        fontWeight: FontWeight.w500,
                                      ),
                                    ),
                                  ],
                                ],
                              ),
                              loading: () => const SizedBox.shrink(),
                              error: (_, __) => const SizedBox.shrink(),
                            ),
                          ],
                        ),
                      ],
                    ),
                  ),
                ],
              ),
            ),
          ),
          const SizedBox(height: 16),
          // iLens 설정 카드
          const Expanded(child: ILensSettingsCard()),
        ],
      ),
    );
  }

  Widget _buildDisconnectedUI(
    List ilensScannedDevices,
    ILensScannedDevicesNotifier notifier,
    bool isScanning,
  ) {
    return SingleChildScrollView(
      child: Padding(
        padding: const EdgeInsets.symmetric(horizontal: 24, vertical: 24),
        child: Column(
          children: [
            const SizedBox(height: 40),
            // 메인 카드
            Card(
              elevation: 4,
              shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(20)),
              child: Padding(
                padding: const EdgeInsets.symmetric(vertical: 48, horizontal: 32),
                child: Column(
                  mainAxisSize: MainAxisSize.min,
                  children: [
                    if (isScanning) ...[
                      // 스캔 중 애니메이션
                      Container(
                        width: 100,
                        height: 100,
                        decoration: BoxDecoration(
                          shape: BoxShape.circle,
                          color: Colors.blue.shade50,
                        ),
                        child: const Center(
                          child: SizedBox(
                            width: 60,
                            height: 60,
                            child: CircularProgressIndicator(
                              strokeWidth: 4,
                            ),
                          ),
                        ),
                      ),
                      const SizedBox(height: 32),
                      Text(
                        'RunVision 검색 중',
                        style: TextStyle(
                          fontSize: 22,
                          fontWeight: FontWeight.bold,
                          color: Colors.blue.shade700,
                        ),
                      ),
                      const SizedBox(height: 12),
                      Text(
                        '주변의 RunVision 기기를 찾고 있습니다...',
                        style: TextStyle(
                          fontSize: 14,
                          color: Colors.grey.shade600,
                        ),
                        textAlign: TextAlign.center,
                      ),
                    ] else ...[
                      // 검색 실패 또는 대기 상태
                      Container(
                        width: 100,
                        height: 100,
                        decoration: BoxDecoration(
                          shape: BoxShape.circle,
                          color: Colors.orange.shade50,
                        ),
                        child: Icon(
                          Icons.bluetooth_searching,
                          size: 50,
                          color: Colors.orange.shade400,
                        ),
                      ),
                      const SizedBox(height: 32),
                      const Text(
                        'RunVision을 찾을 수 없습니다',
                        style: TextStyle(
                          fontSize: 22,
                          fontWeight: FontWeight.bold,
                        ),
                        textAlign: TextAlign.center,
                      ),
                      const SizedBox(height: 12),
                      Text(
                        'RunVision 전원이 켜져 있고\n블루투스가 활성화되어 있는지 확인하세요',
                        style: TextStyle(
                          fontSize: 14,
                          color: Colors.grey.shade600,
                          height: 1.5,
                        ),
                        textAlign: TextAlign.center,
                      ),
                      const SizedBox(height: 32),
                      SizedBox(
                        width: double.infinity,
                        height: 50,
                        child: ElevatedButton.icon(
                          onPressed: () => _autoScanAndConnect(),
                          icon: const Icon(Icons.refresh),
                          label: const Text(
                            '다시 검색',
                            style: TextStyle(fontSize: 16, fontWeight: FontWeight.bold),
                          ),
                          style: ElevatedButton.styleFrom(
                            backgroundColor: Colors.blue,
                            foregroundColor: Colors.white,
                            shape: RoundedRectangleBorder(
                              borderRadius: BorderRadius.circular(12),
                            ),
                          ),
                        ),
                      ),
                    ],
                  ],
                ),
              ),
            ),
            const SizedBox(height: 24),
            // 발견된 기기 목록
            if (ilensScannedDevices.isNotEmpty) ...[
              const Text(
                '발견된 기기',
                style: TextStyle(
                  fontSize: 16,
                  fontWeight: FontWeight.bold,
                  color: Colors.grey,
                ),
              ),
              const SizedBox(height: 12),
              ...ilensScannedDevices.map((device) {
                final deviceName = device.platformName.isEmpty
                    ? device.remoteId.str
                    : device.platformName;

                return Card(
                  margin: const EdgeInsets.only(bottom: 8),
                  child: ListTile(
                    leading: Container(
                      width: 40,
                      height: 40,
                      decoration: BoxDecoration(
                        color: Colors.blue.shade50,
                        borderRadius: BorderRadius.circular(10),
                      ),
                      child: Icon(Icons.bluetooth, color: Colors.blue.shade700),
                    ),
                    title: Text(
                      deviceName,
                      style: const TextStyle(fontWeight: FontWeight.w600),
                    ),
                    subtitle: Text(
                      device.remoteId.str,
                      style: TextStyle(fontSize: 12, color: Colors.grey.shade500),
                    ),
                    trailing: const Icon(Icons.chevron_right),
                    onTap: () async {
                      try {
                        await notifier.connect(device.remoteId.str);
                        await _saveILensDevice(device.remoteId.str, deviceName);
                        ref.read(ilensConnectedDeviceNameProvider.notifier).state = deviceName;
                      } catch (e) {
                        if (mounted) {
                          ScaffoldMessenger.of(context).showSnackBar(
                            SnackBar(
                              content: Text('연결 실패: $e'),
                              backgroundColor: Colors.red,
                            ),
                          );
                        }
                      }
                    },
                  ),
                );
              }),
              const SizedBox(height: 24),
            ],
          ],
        ),
      ),
    );
  }
}

